/**
 * @fileoverview Componente do Cabeçalho Superior (TopBar) do SupliList v3.0 (Void Edition).
 * Gerencia a atualização dinâmica de breadcrumbs baseada em rotas, o badge numérico
 * de notificações de estoque urgente, e redirecionamentos para stack, histórico e settings.
 * 
 * @author SupliList Team
 * @version 3.0.0
 */

import { eventBus } from '../core/eventbus.js';
import { ErrorBoundary } from '../core/error-boundary.js';
import { logger } from '../utils/logger.js';
import { inventoryRepo } from '../features/inventory/inventoryRepo.js';

export class TopBar {
  /**
   * Construtor do TopBar.
   * @param {HTMLElement | string} container - Contêiner pai ou seletor CSS do cabeçalho.
   */
  constructor(container) {
    /**
     * Elemento DOM contêiner do TopBar.
     * @type {HTMLElement | null}
     */
    this.container = typeof container === 'string' ? document.querySelector(container) : container;

    if (!this.container) {
      logger.error('TopBar: O elemento de contêiner não foi localizado no DOM.');
      return;
    }

    /**
     * Mapeamento canônico de rotas do roteador para textos estruturados de Breadcrumb.
     * @type {Record<string, string>}
     */
    this.breadcrumbMap = {
      '/home': 'Home',
      '/list': 'Home / Catálogo',
      '/my-stack': 'Home / Meu Protocolo',
      '/favorites': 'Home / Favoritos',
      '/history': 'Home / Histórico',
      '/dosage': 'Home / Calculadora',
      '/settings': 'Home / Configurações'
    };

    /**
     * Coleção de callbacks de desinscrição do EventBus.
     * @private
     * @type {Function[]}
     */
    this._cleanupFns = [];

    // Vincula o escopo do objeto aos métodos ouvintes
    this._handleRouterNavigate = this._handleRouterNavigate.bind(this);
    this._handleInventoryUrgent = this._handleInventoryUrgent.bind(this);
    this._handleInventoryUpdated = this._handleInventoryUpdated.bind(this);
  }

  /**
   * Inicializa o cabeçalho superior no DOM, vinculando os eventos e ouvintes de navegação/estoque.
   * @returns {void}
   */
  mount() {
    if (!this.container) return;

    // Envolve a inicialização interna com a proteção contra panes do ErrorBoundary
    const safeMount = ErrorBoundary.wrap(() => {
      this._mountInner();
      return this.container;
    }, 'TopBar');

    safeMount();
  }

  /**
   * Método privado para execução síncrona dos registros de eventos e bindings na montagem.
   * @private
   * @returns {void}
   */
  _mountInner() {
    // 1. Vincula cliques nos botões de controle de ações superiores (Event Delegation no container)
    this.container.addEventListener('click', (e) => {
      const btn = e.target.closest('.btn-icon');
      if (!btn) return;

      const btnId = btn.id;
      if (!btnId) return;

      e.preventDefault();
      e.stopPropagation();

      switch (btnId) {
        case 'notification-btn':
          // Vai para /my-stack (Meu Protocolo) para gerenciar reposição
          window.location.hash = '#/my-stack';
          break;
        case 'dashboard-btn':
          // Vai para /history (Dashboard e Timeline de Adesão)
          window.location.hash = '#/history';
          break;
        case 'profile-btn':
          // Abre tela/seção de configurações
          window.location.hash = '#/settings';
          break;
        case 'hamburger-btn':
          // Mobile drawer toggle manual (blindagem caso o drawerSidebar ative atrasado)
          const sidebar = document.getElementById('sidebar');
          if (sidebar) {
            sidebar.classList.toggle('open');
          }
          break;
      }
    });

    // 2. Inscreve ouvintes nos barramentos de reatividade do EventBus
    this._cleanupFns.push(eventBus.on('router:navigate', this._handleRouterNavigate));
    this._cleanupFns.push(eventBus.on('inventory:urgent', this._handleInventoryUrgent));
    this._cleanupFns.push(eventBus.on('inventory:updated', this._handleInventoryUpdated));
    this._cleanupFns.push(eventBus.on('state:imported', this._handleInventoryUpdated));

    // 3. Inicializa o estado de notificações e breadcrumbs com base nos repositórios ativos
    this._updateUrgentBadge();
    
    // Tenta atualizar breadcrumb com a rota atual do browser (se disponível)
    const currentHash = window.location.hash;
    if (currentHash) {
      this._updateBreadcrumbFromRoute(currentHash);
    }
  }

  /**
   * Atualiza dinamicamente o texto informativo de breadcrumb no cabeçalho.
   * @param {string} breadcrumbText - O texto a ser exibido (ex: "Home / Favoritos").
   * @returns {void}
   */
  setBreadcrumb(breadcrumbText) {
    if (!this.container) return;

    const el = this.container.querySelector('#breadcrumb');
    if (el) {
      el.textContent = breadcrumbText || 'Home';
    }
  }

  /**
   * Modifica cirurgicamente o badge de alertas de notificação urgentes.
   * @param {number} count - Número de alertas ativos. Se zero, oculta o badge.
   * @returns {void}
   */
  setNotificationBadge(count) {
    if (!this.container) return;

    const notificationBtn = this.container.querySelector('#notification-btn');
    if (!notificationBtn) return;

    let badge = notificationBtn.querySelector('.notification-badge');

    if (count > 0) {
      if (!badge) {
        badge = document.createElement('span');
        badge.className = 'notification-badge';
        
        // Estilização premium ultravioleta baseada nos tokens HSL/CSS do Design System Void
        Object.assign(badge.style, {
          position: 'absolute',
          top: '2px',
          right: '2px',
          backgroundColor: 'var(--danger)',
          color: '#ffffff',
          fontSize: '9px',
          fontWeight: 'bold',
          width: '15px',
          height: '15px',
          borderRadius: '50%',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          border: '1.5px solid var(--bg-base)',
          boxShadow: '0 0 8px rgba(239, 68, 68, 0.45)',
          pointerEvents: 'none'
        });

        notificationBtn.style.position = 'relative';
        notificationBtn.appendChild(badge);
      }
      badge.textContent = count.toString();
      badge.style.display = 'flex';
      badge.classList.remove('hidden');
    } else {
      if (badge) {
        badge.style.display = 'none';
        badge.classList.add('hidden');
      }
    }
  }

  /**
   * Helper privado para traduzir rota e atualizar breadcrumb dinamicamente.
   * @private
   * @param {string} route - Rota destino.
   * @returns {void}
   */
  _updateBreadcrumbFromRoute(route) {
    let cleanRoute = route || '/list';
    if (cleanRoute.startsWith('#')) {
      cleanRoute = cleanRoute.slice(1);
    }
    if (!cleanRoute.startsWith('/')) {
      cleanRoute = '/' + cleanRoute;
    }

    const breadcrumbText = this.breadcrumbMap[cleanRoute] || 'Home';
    this.setBreadcrumb(breadcrumbText);
  }

  /**
   * Ouvinte reativo disparado após transições do roteador.
   * @private
   * @param {{ route: string }} payload - Dados de navegação.
   * @returns {void}
   */
  _handleRouterNavigate({ route }) {
    this._updateBreadcrumbFromRoute(route);
  }

  /**
   * Ouvinte reativo disparado após emissão de alertas críticos de estoque.
   * @private
   * @param {{ supplements: Array<any> }} payload - Alertas de estoque baixo.
   * @returns {void}
   */
  _handleInventoryUrgent(payload) {
    if (payload && Array.isArray(payload.supplements)) {
      this.setNotificationBadge(payload.supplements.length);
    }
  }

  /**
   * Ouvinte reativo disparado quando o inventário sofre mutações normais.
   * @private
   * @returns {void}
   */
  _handleInventoryUpdated() {
    this._updateUrgentBadge();
  }

  /**
   * Helper privado para recalcular itens sob urgência e readequar contagem do badge.
   * @private
   * @returns {void}
   */
  _updateUrgentBadge() {
    try {
      const audit = inventoryRepo.checkUrgent();
      this.setNotificationBadge(audit.items.length);
    } catch (err) {
      logger.error('TopBar: Falha ao obter dados urgentes do estoque.', err);
    }
  }

  /**
   * Libera listeners e limpa inscrições reativas de eventos para prevenção de memory leaks.
   * @returns {void}
   */
  destroy() {
    this._cleanupFns.forEach((fn) => {
      try {
        fn();
      } catch (err) {
        // Ignora desinscrições individuais malsucedidas
      }
    });
    this._cleanupFns = [];

    logger.info('TopBar destruído com sucesso.');
  }
}
