/**
 * @fileoverview Controlador da Página de Configurações (SettingsPage) do SupliList v3.0.
 * Oferece interface de usuário para alternar temas, limpar banco local de preferências e controle reativo.
 * 
 * @author SupliList Team
 * @version 3.0.0
 */

import { stateManager } from '../core/state-manager.js';
import { eventBus } from '../core/eventbus.js';
import { ErrorBoundary } from '../core/error-boundary.js';
import { logger } from '../utils/logger.js';
import { toast } from './toast.js';
import { settingsRepo } from '../features/settings/settingsRepo.js';
import { notificationScheduler } from '../features/settings/notificationScheduler.js';

class SettingsPageController {
  constructor(container) {
    this.container = typeof container === 'string' ? document.querySelector(container) : container;
    
    if (!this.container) {
      logger.error('SettingsPageController: Elemento contêiner inválido.');
      return;
    }
  }

  init() {
    this.render();
    this._setupListeners();
  }

  render() {
    const currentTheme = stateManager.getState('settings.theme') || 'dark';
    const notificationsEnabled = settingsRepo.getSetting('notificationsEnabled') || false;

    this.container.innerHTML = `
      <div class="settings-container max-w-4xl mx-auto p-6 flex flex-col gap-6 animate-fade-in">
        <div class="bg-zinc-900/40 border border-zinc-800/30 rounded-3xl p-6 md:p-8 flex flex-col gap-6">
          <h1 class="font-extrabold text-2xl text-zinc-100 flex items-center gap-2">⚙️ Configurações</h1>
          <p class="text-xs text-zinc-400 leading-relaxed">
            Customize o comportamento do aplicativo SupliList, alterne temas e faça a limpeza ou importação de seus dados locais de forma simples.
          </p>

          <div class="flex flex-col gap-4 mt-4">
            <!-- Alternar Tema -->
            <div class="flex items-center justify-between p-4 bg-zinc-950/40 rounded-2xl border border-zinc-800/40">
              <div>
                <span class="text-xs font-bold text-zinc-100 block">Tema Visual</span>
                <span class="text-[10px] text-zinc-500">Alternar entre Dark Mode e Light Mode.</span>
              </div>
              <button id="toggle-theme-btn" class="px-4 py-2 bg-zinc-800 hover:bg-zinc-700 text-zinc-200 text-xs font-bold rounded-xl transition-all shadow-sm focus:outline-none">
                Alternar (${currentTheme === 'dark' ? 'Tema Escuro' : 'Tema Claro'})
              </button>
            </div>

            <!-- Notificações PWA -->
            <div class="flex items-center justify-between p-4 bg-zinc-950/40 rounded-2xl border border-zinc-800/40">
              <div>
                <span class="text-xs font-bold text-zinc-100 block">Notificações de Reposição</span>
                <span class="text-[10px] text-zinc-500">Alertas diários sobre suplementos acabando em seu estoque.</span>
              </div>
              <div class="flex items-center gap-2">
                ${notificationsEnabled ? `
                  <button id="test-notify-btn" class="px-3 py-2 bg-purple-950/20 hover:bg-purple-950/40 border border-purple-900/35 text-purple-300 text-[11px] font-bold rounded-xl transition-all focus:outline-none">
                    Testar Notificação
                  </button>
                ` : ''}
                <button id="toggle-notifications-btn" class="px-4 py-2 ${notificationsEnabled ? 'bg-red-950/20 hover:bg-red-950/40 border border-red-900/35 text-red-200' : 'bg-zinc-800 hover:bg-zinc-700 text-zinc-200'} text-xs font-bold rounded-xl transition-all shadow-sm focus:outline-none">
                  ${notificationsEnabled ? 'Desativar' : 'Ativar'}
                </button>
              </div>
            </div>

            <!-- Limpar Dados -->
            <div class="flex items-center justify-between p-4 bg-zinc-950/40 rounded-2xl border border-zinc-800/40">
              <div>
                <span class="text-xs font-bold text-zinc-100 block">Limpeza de Cache Local</span>
                <span class="text-[10px] text-zinc-500 text-red-400">ATENÇÃO: Apaga permanentemente seus favoritos, históricos e check-ins.</span>
              </div>
              <button id="reset-data-btn" class="px-4 py-2 bg-red-950/20 hover:bg-red-950/40 border border-red-900/35 text-red-200 text-xs font-bold rounded-xl transition-all focus:outline-none">
                Apagar Dados
              </button>
            </div>
          </div>
        </div>
      </div>
    `;
  }

  _setupListeners() {
    const themeBtn = this.container.querySelector('#toggle-theme-btn');
    if (themeBtn) {
      themeBtn.addEventListener('click', () => {
        const currentTheme = settingsRepo.getSetting('theme') || 'dark';
        const newTheme = currentTheme === 'dark' ? 'light' : 'dark';
        
        settingsRepo.setSetting('theme', newTheme);
        
        toast.show(`Tema alterado para ${newTheme === 'dark' ? 'Escuro' : 'Claro'}!`, 'success');
        this.render();
        this._setupListeners();
      });
    }

    const notifyToggleBtn = this.container.querySelector('#toggle-notifications-btn');
    if (notifyToggleBtn) {
      notifyToggleBtn.addEventListener('click', async () => {
        const currentlyEnabled = settingsRepo.getSetting('notificationsEnabled') || false;
        
        if (!currentlyEnabled) {
          const granted = await notificationScheduler.requestPermission();
          if (granted) {
            settingsRepo.setSetting('notificationsEnabled', true);
            toast.show('🔔 Notificações de reposição ativadas!', 'success');
            notificationScheduler.triggerNotification(
              'SupliList — Notificações Ativadas! 🔔',
              'Você receberá lembretes diários inteligentes quando seus suplementos estiverem acabando.',
              '#/settings'
            );
          } else {
            toast.show('⚠️ Permissão de notificação foi negada pelo navegador.', 'warning');
            settingsRepo.setSetting('notificationsEnabled', false);
          }
        } else {
          settingsRepo.setSetting('notificationsEnabled', false);
          toast.show('🔕 Notificações desativadas.', 'info');
        }
        
        this.render();
        this._setupListeners();
      });
    }

    const testNotifyBtn = this.container.querySelector('#test-notify-btn');
    if (testNotifyBtn) {
      testNotifyBtn.addEventListener('click', () => {
        notificationScheduler.checkAndNotify(true);
        toast.show('Enviando notificação de teste...', 'info');
      });
    }

    const resetBtn = this.container.querySelector('#reset-data-btn');
    if (resetBtn) {
      resetBtn.addEventListener('click', () => {
        if (confirm('Tem certeza que deseja apagar permanentemente todas as suas preferências, favoritos e históricos?')) {
          localStorage.clear();
          toast.show('Todos os dados locais foram excluídos com sucesso. Recarregando...', 'warning');
          setTimeout(() => location.reload(), 1500);
        }
      });
    }
  }

  destroy() {
    logger.info('SettingsPageController destruído.');
  }
}

const _createSettingsPage = (container = '#page-content') => {
  const controller = new SettingsPageController(container);
  controller.init();
  return controller;
};

export const createSettingsPage = _createSettingsPage;
